export async function DELETE(req, { params }) {
  const supabase = await createClient()  // 세션 확인용
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return Response.json({error: '인증 필요'}, {status: 401})

  const adminCheckClient = createAdminClient()
  const { data: authUser } = await adminCheckClient.auth.admin.getUserById(user.id)
  if (authUser.user.app_metadata?.role !== 'admin')
    return Response.json({error: '권한 없음'}, {status: 403})

  const { error } = await adminCheckClient
    .from('events')
    .delete()
    .eq('id', params.id)

  if (error) return Response.json({error: error.message}, {status: 500})
  return Response.json({success: true})
}
