'use client'
interface Props { eventId: string; eventTitle: string }

export function EventDeleteButton({ eventId, eventTitle }: Props) {
  const router = useRouter()
  const [loading, setLoading] = useState(false)

  async function handleDelete() {
    if (!confirm(`'${eventTitle}' 이벤트를 삭제하시겠습니까?`)) return
    setLoading(true)
    try {
      const res = await fetch(`/api/admin/events/${eventId}`, { method: 'DELETE' })
      if (!res.ok) throw new Error((await res.json()).error)
      router.refresh()
    } catch (e) {
      alert('삭제 실패: ' + e.message)
    } finally {
      setLoading(false)
    }
  }

  return <Button variant='destructive' size='sm' onClick={handleDelete} disabled={loading}>
    {loading ? '삭제 중...' : '삭제'}
  </Button>
}
